mapper.update:
Update student
name = #{name}, no = #{no}, gender = #{gender}, phone = #{phone}, degree = #{degree}, id_card = #{idCard}, is_college = #{isCollege}, address = #{address}, graduation_date = #{graduationDate}, violation_count = #{violationCount}, violation_score = #{violationScore}, clazz_id = #{clazzId}, update_time = #{updateTime},
WHERE id = #{id}

UPDATE student
SET violation_score = violation_score + #{score}, violation_count = violation_count + 1
WHERE id = #{id}

mapper.select:
SELECT s.id, s.name, s.no, s.gender, s.phone, s.degree, s.id_card, s.is_college, s.address, s.graduation_date, s.violation_count, s.violation_score, s.clazz_id, c.name AS clazz_name, s.create_time, s.update_time FROM student AS s LEFT JOIN clazz AS c ON s.clazz_id = c.id
s.name LIKE CONCAT ( '%', #{name}, '%' )
AND s.degree = #{degree}
AND s.clazz_id = #{clazzId}
ORDER BY s.id
